parameters.jsCode:
let raw = $json.output ?? '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

// Garante que será considerado apenas o conteúdo JSON
const inicioJson = raw.indexOf('{');
const fimJson = raw.lastIndexOf('}');

if (inicioJson !== -1 && fimJson !== -1) {
  raw = raw.substring(inicioJson, fimJson + 1);
}

// Remove vírgulas sobrando antes de fechar objeto ou array
raw = raw.replace(/,\s*([}\]])/g, '$1');

let dados;

try {
  dados = JSON.parse(raw);
} catch (error) {
  // Fallback para não quebrar o fluxo caso o agente retorne JSON inválido
  dados = {
    nome: $json.nome || '',
    email: $json.email || '',
    descricao_da_vaga: $json.descricao_da_vaga || '',
    modalidade: $json.modalidade || '',
    score_vaga: 0,
    score_ats: 0,
    status_ats: 'Não informado',
    recomendacao: 'Análise gerada com inconsistência no JSON do agente',
    pontos_fortes_match: [],
    lacunas_match: [],
    pontos_fortes_curriculo: [],
    melhorias_curriculo: [],
    parecer_final: raw
  };
}

const documento = ($json.documento || '')
  .replace(/[^a-zA-Z0-9]/g, '')
  .toUpperCase();

const lista = (itens) => {
  if (!Array.isArray(itens) || itens.length === 0) {
    return '<li>Não informado</li>';
  }

  return itens.map(item => `<li>${item}</li>`).join('');
};

const scoreVaga = Number(dados.score_vaga || 0);
const scoreAts = Number(dados.score_ats || 0);

const html_email = `
<div style="font-family: Arial, sans-serif; background:#f4f6f8; padding:24px;">
  <div style="max-width:720px; margin:0 auto; background:#ffffff; border-radius:12px; overflow:hidden; border:1px solid #e5e7eb;">

    <div style="background:#0f172a; color:#ffffff; padding:28px;">
      <h1 style="margin:0; font-size:26px;">ATS Inteligente</h1>
      <p style="margin:8px 0 0; font-size:15px;">Relatório Executivo de Triagem de Currículo</p>
    </div>

    <div style="padding:24px;">
      <h2 style="font-size:18px; color:#111827; margin:0 0 16px;">Dados do Candidato</h2>
      <p><strong>Nome:</strong> ${$json.nome || dados.nome || 'Não informado'}</p>
      <p><strong>E-mail:</strong> ${$json.email || dados.email || 'Não informado'}</p>
      <p><strong>Documento:</strong> ${documento || 'Não informado'}</p>
      <p><strong>Modalidade:</strong> ${$json.modalidade || dados.modalidade || 'Não informado'}</p>
      <p><strong>Área profissional:</strong> ${dados.area_profissional || 'Não informado'}</p>
      <p><strong>Senioridade:</strong> ${dados.senioridade || 'Não informado'}</p>
    </div>

    <div style="padding:24px; background:#f9fafb; border-top:1px solid #e5e7eb;">
      <h2 style="font-size:18px; color:#111827; margin:0 0 16px;">Resultado da Avaliação</h2>

      <p><strong>Score da Vaga:</strong> ${scoreVaga}%</p>
      <div style="background:#e5e7eb; border-radius:999px; height:12px; overflow:hidden; margin-bottom:14px;">
        <div style="background:#2563eb; width:${scoreVaga}%; height:12px;"></div>
      </div>

      <p><strong>Score ATS:</strong> ${scoreAts}%</p>
      <div style="background:#e5e7eb; border-radius:999px; height:12px; overflow:hidden; margin-bottom:14px;">
        <div style="background:#16a34a; width:${scoreAts}%; height:12px;"></div>
      </div>

      <p><strong>Status ATS:</strong> ${dados.status_ats || 'Não informado'}</p>
      <p><strong>Recomendação:</strong> ${dados.recomendacao || 'Não informado'}</p>
    </div>

    <div style="padding:24px;">
      <h2 style="font-size:18px; color:#111827;">Match com a Vaga</h2>

      <h3 style="font-size:15px; color:#166534;">Pontos fortes</h3>
      <ul>${lista(dados.pontos_fortes_match)}</ul>

      <h3 style="font-size:15px; color:#92400e;">Lacunas identificadas</h3>
      <ul>${lista(dados.lacunas_match)}</ul>
    </div>

    <div style="padding:24px; background:#f9fafb; border-top:1px solid #e5e7eb;">
      <h2 style="font-size:18px; color:#111827;">Auditoria do Currículo</h2>

      <h3 style="font-size:15px; color:#166534;">Pontos fortes do currículo</h3>
      <ul>${lista(dados.pontos_fortes_curriculo)}</ul>

      <h3 style="font-size:15px; color:#92400e;">Melhorias recomendadas</h3>
      <ul>${lista(dados.melhorias_curriculo)}</ul>
    </div>

    <div style="padding:24px;">
      <h2 style="font-size:18px; color:#111827;">Parecer Final</h2>
      <p style="line-height:1.6;">${dados.parecer_final || 'Não informado'}</p>
    </div>

    <div style="padding:24px; background:#0f172a; color:#ffffff; text-align:center;">
      <p style="margin:0; font-size:18px; font-weight:bold;">${dados.recomendacao || 'Não informado'}</p>
      <p style="margin:8px 0 0; font-size:12px;">Relatório gerado automaticamente pelo ATS Inteligente</p>
    </div>

  </div>
</div>
`;

return [
  {
    json: {
      nome: $json.nome || dados.nome || '',
      email: $json.email || dados.email || '',
      documento,
      descricao_da_vaga: $json.descricao_da_vaga || dados.descricao_da_vaga || '',
      modalidade: $json.modalidade || dados.modalidade || '',
      html_email
    }
  }
];
